import React, { useState } from 'react';
import { Container, Card, Form, Button, Row, Col, Alert } from 'react-bootstrap';
import { LinkContainer } from 'react-router-bootstrap';
import { useAuth } from '../context/AuthContext';

const SimpleDietForm = () => {
  const { token, user } = useAuth();
  const [formData, setFormData] = useState({
    weight: '',
    height: '',
    age: '',
    gender: '',
    activityLevel: 'moderate',
    goal: 'maintenance',
    dietaryRestrictions: [],
    allergies: '',
    mealsPerDay: '3',
    waterIntake: '8',
    sleepHours: '',
    medicalConditions: ''
  });
  const [recommendation, setRecommendation] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    if (type === 'checkbox') {
      setFormData(prev => ({
        ...prev,
        [name]: checked
          ? [...prev.dietaryRestrictions, value]
          : prev.dietaryRestrictions.filter(item => item !== value)
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const generateSimpleRecommendation = (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    if (!token) {
      setError('Please login to generate diet recommendations');
      setLoading(false);
      return;
    }

    try {
      // Simple recommendation logic without backend API
      const weight = parseFloat(formData.weight) || 70;
      const height = parseFloat(formData.height) || 170;
      const age = parseInt(formData.age) || 25;
      const gender = formData.gender || 'male';
      const activityLevel = formData.activityLevel || 'moderate';
      const goal = formData.goal || 'maintenance';

      // Calculate BMI
      const heightM = height / 100;
      const bmi = weight / (heightM * heightM);

      // Calculate BMR using Mifflin-St Jeor Equation
      let bmr;
      if (gender === 'male') {
        bmr = 10 * weight + 6.25 * height - 5 * age + 5;
      } else {
        bmr = 10 * weight + 6.25 * height - 5 * age - 161;
      }

      // Activity multipliers
      const activityMultipliers = {
        sedentary: 1.2,
        light: 1.375,
        moderate: 1.55,
        active: 1.725,
        very_active: 1.9
      };

      const tdee = bmr * (activityMultipliers[activityLevel] || 1.55);

      // Adjust calories based on goal
      let dailyCalories = tdee;
      let goalText = 'maintenance';

      if (goal === 'weight_loss') {
        dailyCalories = tdee * 0.85; // 15% deficit
        goalText = 'weight loss';
      } else if (goal === 'weight_gain') {
        dailyCalories = tdee * 1.15; // 15% surplus
        goalText = 'weight gain';
      }

      // Calculate macros (40% carbs, 30% protein, 30% fats)
      const macros = {
        carbs: Math.round((dailyCalories * 0.40) / 4),
        protein: Math.round((dailyCalories * 0.30) / 4),
        fats: Math.round((dailyCalories * 0.30) / 9)
      };

      // Generate meal plan
      const mealPlan = generateMealPlan(macros, formData.mealsPerDay || 3);

      const recommendation = {
        bmi: bmi.toFixed(1),
        bmiCategory: getBMICategory(bmi),
        dailyCalories: Math.round(dailyCalories),
        goal: goalText,
        macros,
        mealPlan,
        waterIntake: (weight * 35).toFixed(0), // 35ml per kg
        generatedAt: new Date().toLocaleString()
      };

      setRecommendation(recommendation);
    } catch (error) {
      setError('Failed to generate recommendation. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const getBMICategory = (bmi) => {
    if (bmi < 18.5) return 'Underweight';
    if (bmi < 25) return 'Normal weight';
    if (bmi < 30) return 'Overweight';
    return 'Obese';
  };

  const generateMealPlan = (macros, mealsPerDay) => {
    const meals = [];
    const proteinPerMeal = Math.round(macros.protein / mealsPerDay);
    const carbsPerMeal = Math.round(macros.carbs / mealsPerDay);
    const fatsPerMeal = Math.round(macros.fats / mealsPerDay);

    const mealNames = ['Breakfast', 'Lunch', 'Dinner', 'Snack'];
    const foods = {
      breakfast: ['Oatmeal with fruits', 'Eggs with toast', 'Greek yogurt with nuts'],
      lunch: ['Grilled chicken salad', 'Quinoa bowl', 'Turkey sandwich'],
      dinner: ['Grilled salmon', 'Lean beef with vegetables', 'Pasta with sauce'],
      snack: ['Apple with peanut butter', 'Protein shake', 'Mixed nuts']
    };

    for (let i = 0; i < mealsPerDay; i++) {
      const mealType = i < 3 ? ['breakfast', 'lunch', 'dinner'][i] : 'snack';
      const foodOptions = foods[mealType];
      const selectedFood = foodOptions[Math.floor(Math.random() * foodOptions.length)];

      meals.push({
        name: mealNames[i] || `Meal ${i + 1}`,
        food: selectedFood,
        protein: proteinPerMeal,
        carbs: carbsPerMeal,
        fats: fatsPerMeal,
        calories: (proteinPerMeal * 4) + (carbsPerMeal * 4) + (fatsPerMeal * 9)
      });
    }

    return meals;
  };

  return (
    <Container className="mt-4">
      <h2 className="mb-4">Simple Diet Plan Generator</h2>

      <Alert variant="info" className="mb-4">
        <h6 className="alert-heading">🥗 Simple Diet Recommendation</h6>
        <p className="mb-2">
          This is a simplified diet plan generator that works without the backend API.
          Fill in your details below to get a personalized diet recommendation.
        </p>
        <hr />
        <p className="mb-0 text-muted small">
          Note: This is a basic recommendation. Consult a healthcare professional for personalized advice.
        </p>
      </Alert>

      <Row>
        <Col md={6}>
          <Card>
            <Card.Header>
              <h5 className="mb-0">Your Information</h5>
            </Card.Header>
            <Card.Body>
              <Form onSubmit={generateSimpleRecommendation}>
                <Row>
                  <Col md={6}>
                    <Form.Group className="mb-3">
                      <Form.Label>Weight (kg)</Form.Label>
                      <Form.Control
                        type="number"
                        name="weight"
                        value={formData.weight}
                        onChange={handleChange}
                        placeholder="70"
                        step="0.1"
                      />
                    </Form.Group>
                  </Col>
                  <Col md={6}>
                    <Form.Group className="mb-3">
                      <Form.Label>Height (cm)</Form.Label>
                      <Form.Control
                        type="number"
                        name="height"
                        value={formData.height}
                        onChange={handleChange}
                        placeholder="170"
                      />
                    </Form.Group>
                  </Col>
                </Row>

                <Row>
                  <Col md={6}>
                    <Form.Group className="mb-3">
                      <Form.Label>Age</Form.Label>
                      <Form.Control
                        type="number"
                        name="age"
                        value={formData.age}
                        onChange={handleChange}
                        placeholder="25"
                      />
                    </Form.Group>
                  </Col>
                  <Col md={6}>
                    <Form.Group className="mb-3">
                      <Form.Label>Gender</Form.Label>
                      <Form.Select name="gender" value={formData.gender} onChange={handleChange}>
                        <option value="">Select</option>
                        <option value="male">Male</option>
                        <option value="female">Female</option>
                      </Form.Select>
                    </Form.Group>
                  </Col>
                </Row>

                <Row>
                  <Col md={6}>
                    <Form.Group className="mb-3">
                      <Form.Label>Activity Level</Form.Label>
                      <Form.Select name="activityLevel" value={formData.activityLevel} onChange={handleChange}>
                        <option value="sedentary">Sedentary</option>
                        <option value="light">Lightly Active</option>
                        <option value="moderate">Moderately Active</option>
                        <option value="active">Very Active</option>
                        <option value="very_active">Extra Active</option>
                      </Form.Select>
                    </Form.Group>
                  </Col>
                  <Col md={6}>
                    <Form.Group className="mb-3">
                      <Form.Label>Goal</Form.Label>
                      <Form.Select name="goal" value={formData.goal} onChange={handleChange}>
                        <option value="maintenance">Maintain Weight</option>
                        <option value="weight_loss">Lose Weight</option>
                        <option value="weight_gain">Gain Weight</option>
                      </Form.Select>
                    </Form.Group>
                  </Col>
                </Row>

                <Form.Group className="mb-3">
                  <Form.Label>Meals Per Day</Form.Label>
                  <Form.Select name="mealsPerDay" value={formData.mealsPerDay} onChange={handleChange}>
                    <option value="3">3 Meals</option>
                    <option value="4">4 Meals</option>
                    <option value="5">5 Meals</option>
                  </Form.Select>
                </Form.Group>

                {error && <Alert variant="danger">{error}</Alert>}

                <Button variant="primary" type="submit" className="w-100" disabled={loading}>
                  {loading ? 'Generating...' : '🥗 Generate Diet Plan'}
                </Button>
              </Form>
            </Card.Body>
          </Card>
        </Col>

        <Col md={6}>
          {recommendation && (
            <Card>
              <Card.Header>
                <h5 className="mb-0">Your Diet Plan</h5>
              </Card.Header>
              <Card.Body>
                <div className="mb-4">
                  <h6>Body Metrics</h6>
                  <p><strong>BMI:</strong> {recommendation.bmi} ({recommendation.bmiCategory})</p>
                  <p><strong>Daily Calories:</strong> {recommendation.dailyCalories} kcal</p>
                  <p><strong>Goal:</strong> {recommendation.goal}</p>
                </div>

                <div className="mb-4">
                  <h6>Daily Macros</h6>
                  <p><strong>Protein:</strong> {recommendation.macros.protein}g</p>
                  <p><strong>Carbs:</strong> {recommendation.macros.carbs}g</p>
                  <p><strong>Fats:</strong> {recommendation.macros.fats}g</p>
                </div>

                <div className="mb-4">
                  <h6>Water Intake</h6>
                  <p><strong>Daily Target:</strong> {recommendation.waterIntake}ml</p>
                  <p><strong>Glasses:</strong> {Math.round(recommendation.waterIntake / 250)} glasses</p>
                </div>

                <div className="mb-4">
                  <h6>Meal Plan</h6>
                  {recommendation.mealPlan.map((meal, index) => (
                    <div key={index} className="mb-3 p-2 border rounded">
                      <strong>{meal.name}:</strong> {meal.food}<br />
                      <small className="text-muted">
                        Protein: {meal.protein}g | Carbs: {meal.carbs}g | Fats: {meal.fats}g | {meal.calories} kcal
                      </small>
                    </div>
                  ))}
                </div>

                <div className="text-muted small">
                  <p><strong>Generated:</strong> {recommendation.generatedAt}</p>
                  <p><em>This is a simplified recommendation for demonstration purposes.</em></p>
                </div>
              </Card.Body>
            </Card>
          )}
        </Col>
      </Row>

      <div className="text-center mt-4">
        <LinkContainer to="/dashboard">
          <Button variant="outline-primary">Back to Dashboard</Button>
        </LinkContainer>
      </div>
    </Container>
  );
};

export default SimpleDietForm;
